import React, { useState } from 'react'; // Importa React e useState para gerenciar estado.
import './novaPessoa.css'; // Importa o CSS para estilização.

const NovaPessoa = () => { // Define o componente funcional 'NovaPessoa'.
    const [formData, setFormData] = useState({ // Cria um estado para armazenar os dados do formulário.
        nome: '',
        cpfCnpj: '',
        telefone: '',
        email: '',
        cidade: '',
        uf: '',
        tipo: 'Física',
        endereco: false,
        criarOutro: false,
    });

    const handleChange = (e) => { // Função para atualizar o estado conforme os campos do formulário são preenchidos.
        const { name, value, type, checked } = e.target;
        setFormData(prevState => ({
            ...prevState,
            [name]: type === 'checkbox' ? checked : value, // Atualiza o valor correto dependendo do tipo do input.
        }));
    };

    const handleSubmit = (e) => { // Função para lidar com a submissão do formulário.
        e.preventDefault(); // Evita o comportamento padrão do formulário.
        // Aqui você pode enviar os dados para o servidor ou processá-los como necessário.
        console.log('Dados enviados:', formData);
    };

    return ( // Início do retorno do JSX do componente.
        <div className="nova-pessoa-container"> {/* Cria uma div para o contêiner do formulário. */}
            <h1>Nova Pessoa</h1> {/* Título do formulário. */}
            <form onSubmit={handleSubmit}> {/* Formulário para adicionar nova pessoa. */}
                <label>
                    Nome*
                    <input 
                        type="text" 
                        name="nome" 
                        value={formData.nome} 
                        onChange={handleChange} 
                        required 
                    />
                </label>
                <label>
                    CPF/CNPJ
                    <input 
                        type="text" 
                        name="cpfCnpj" 
                        value={formData.cpfCnpj} 
                        onChange={handleChange} 
                    />
                </label>
                <label>
                    Telefone
                    <input 
                        type="text" 
                        name="telefone" 
                        value={formData.telefone} 
                        onChange={handleChange} 
                    />
                </label>
                <label>
                    E-mail
                    <input 
                        type="email" 
                        name="email" 
                        value={formData.email} 
                        onChange={handleChange} 
                    />
                </label>
                <label>
                    Cidade
                    <input 
                        type="text" 
                        name="cidade" 
                        value={formData.cidade} 
                        onChange={handleChange} 
                    />
                </label>
                <label>
                    UF
                    <input 
                        type="text" 
                        name="uf" 
                        value={formData.uf} 
                        onChange={handleChange} 
                    />
                </label>
                <label>
                    Tipo
                    <select name="tipo" value={formData.tipo} onChange={handleChange}>
                        <option value="Física">Pessoa Física</option>
                        <option value="Jurídica">Pessoa Jurídica</option>
                    </select>
                </label>
                <label>
                    <input 
                        type="checkbox" 
                        name="endereco" 
                        checked={formData.endereco} 
                        onChange={handleChange} 
                    />
                    Inserir endereço
                </label>
                <label>
                    <input 
                        type="checkbox" 
                        name="criarOutro" 
                        checked={formData.criarOutro} 
                        onChange={handleChange} 
                    />
                    Criar outro
                </label>
                <div className="form-actions"> {/* Div para os botões de ação. */}
                    <button type="button" className="btn-cancelar">Cancelar</button> {/* Botão de cancelar. */}
                    <button type="submit" className="btn-salvar">Salvar</button> {/* Botão para salvar os dados. */}
                </div>
            </form>
        </div> // Fecha o contêiner principal.
    );
}; // Fecha a definição do componente.

export default NovaPessoa; // Exporta o componente 'NovaPessoa'.
